data.content:
MSTest **doesn't have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. Here's what to use instead:

| Need | MSTest Approach |
|---|---|
| `value > x` | `Assert.IsTrue(value > x)` |
| `value >= x` | `Assert.IsTrue(value >= x)` |
| Range check | `Assert.IsTrue(value >= lo && value <= hi)` |
| Exact match | `Assert.AreEqual(expected, actual)` |
| Float tolerance | `Assert.AreEqual(expected, actual, delta)` |
| Exception | `Assert.ThrowsException<T>(action)` |

The `double` overload of `Assert.AreEqual` accepts a **delta** (tolerance) parameter — that's your best tool for floating-point boundary checks.

Here's a test class:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    // ── CalculatePercentage ──

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calc.CalculatePercentage(0, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calc.CalculatePercentage(3, 4), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    // ── GetGrade boundaries ──

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.999, "B")]
    [DataRow(80.0, "B")]
    [DataRow(79.999, "C")]
    [DataRow(70.0, "C")]
    [DataRow(69.999, "D")]
    [DataRow(60.0, "D")]
    [DataRow(59.999, "F")]
    [DataRow(0.0, "F")]
    [DataRow(100.0, "A")]
    public void GetGrade_AtBoundary_ReturnsExpectedGrade(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    // ── NormalizeScore ──

    [TestMethod]
    public void NormalizeScore_HalfRaw_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        // Verifies the Math.Min cap — result must not exceed 100
        double result = _calc.NormalizeScore(120, 100);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_Returns0()
    {
        Assert.AreEqual(0.0, _calc.NormalizeScore(0, 50), 0.001);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(-1, 50));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.NormalizeScore(10, 0));
    }
}
```

**Key patterns used:**
- **`Assert.AreEqual(expected, actual, 0.001)`** — the `delta` parameter handles floating-point imprecision
- **`Assert.ThrowsException<T>`** — validates guard clauses
- **`[DataTestMethod]` + `[DataRow]`** — parameterized tests for grade boundary coverage, testing both sides of each threshold (e.g., `90.0` → A vs `89.999` → B)

If you want a fluent API with real `IsGreaterThan`/`IsInRange`, consider **FluentAssertions** (`value.Should().BeInRange(lo, hi)`), but it's a third-party package.
